-- Transaction control: BEGIN, COMMIT, SAVEPOINT, RELEASE,
-- SET TRANSACTION ISOLATION LEVEL.
--
-- Source: pkg/sql/parser/testdata/begin_commit (cockroachdb/cockroach@release-25.3)
-- Source: pkg/sql/parser/testdata/set (cockroachdb/cockroach@release-25.3)

BEGIN TRANSACTION;
SAVEPOINT cockroach_restart;
SELECT 1;
RELEASE SAVEPOINT cockroach_restart;
COMMIT;

BEGIN TRANSACTION ISOLATION LEVEL SERIALIZABLE;
COMMIT;

BEGIN TRANSACTION ISOLATION LEVEL READ COMMITTED;
COMMIT;

BEGIN TRANSACTION READ ONLY;
SELECT 1;
COMMIT;

BEGIN TRANSACTION PRIORITY HIGH, READ WRITE;
COMMIT;

SET TRANSACTION ISOLATION LEVEL SERIALIZABLE;

SET TRANSACTION ISOLATION LEVEL READ COMMITTED;

SET TRANSACTION READ ONLY;

SAVEPOINT my_savepoint;
ROLLBACK TO SAVEPOINT my_savepoint;
